SELECT /* @SQLID=SUB0404-01#SQL001 */ * FROM ( SELECT COUNT(*) OVER() AS TOTALROW, TMU.USER_ID AS USER_ID, BR.BRANCH_NAME AS BRANCH_NAME, MB.BRANCH_NAME AS BROKER_NAME, TMU.USER_NM AS USER_NM, TMYU.MAIL_ADDRESS AS MAIL_ADDRESS, TMYU.VERIFY_STATUS AS VERIFY_STATUS FROM TB_MED_USERS TMU INNER JOIN TB_MED_VERIFY_USERS TMYU ON TMU.USER_ID = TMYU.USER_ID AND TMYU.VERIFY_STATUS = '1' LEFT OUTER JOIN BRANCH BR ON TMU.BRANCH_ID = BR.BRANCH_CODE LEFT OUTER JOIN MEDIATE_BRANCH MB ON TMU.BROKER_ID = MB.BROKER_CODE AND MB.BROKER_BRANCH_CODE = '999' AND MB.BROKER_BRANCH_KIND = '00' WHERE 1 = 1
AND(TMU.BROKER_ID IN
) OR TMU.BROKER_ID IN(
,
#{brokerCharge.brokerCode}
)
AND((TMU.BROKER_ID, TMU.EMPLOYEE_ID) IN
) OR (TMU.BROKER_ID, TMU.EMPLOYEE_ID) IN(
,
(#{brokerCharge.brokerCode}, #{brokerCharge.empCode})
)
AND TMU.USER_ID LIKE #{userId} ESCAPE '!'
AND (TMU.EMPLOYEE_NAME LIKE #{employeeName} ESCAPE '!' OR TMU.USER_NM LIKE #{employeeName} ESCAPE '!')
AND ( BR.BRANCH_NAME LIKE #{brokerOrBranchName} ESCAPE '!' OR MB.BRANCH_NAME LIKE #{brokerOrBranchName} ESCAPE '!')
ORDER BY USER_ID ASC )
AND ROWNUM <= #{rowNum}

