UPDATE TB_MED_VERIFY_USERS /* @SQLID=SUB0404-02_1#SQL001 */
SET
  MAIL_ADDRESS = #{model.mailAddress}
, UPDATE_DATE  = IFA_DATE_UTIL.IFA_GET_DATE
, UPDATE_BY    = #{model.updateBy}
WHERE
  USER_ID      = #{model.userId}
